<div class="page-header"><div class="container"><h1>📦 My Orders</h1><p>View all your order history</p></div></div>
<div class="container"><?php if ($orders): ?><?php foreach ($orders as $order): ?><div class="order-card"><div class="order-header"><div><div class="order-number">Order #<?= e($order['order_number']) ?></div><div class="order-date"><?= e($order['created_at']) ?></div></div><div style="display:flex;align-items:center;gap:1rem"><span class="badge badge-<?= e($order['status_class']) ?>"><?= e($order['status_label']) ?></span><a href="<?= url_for('order_detail', ['order_number' => $order['order_number']]) ?>" class="btn btn-outline btn-sm">View Details →</a></div></div><div class="status-steps"><span class="step-dot done">📝</span><?php $__ss = $order['shipment_status'] ?? ''; ?><span class="step-dot <?= $__ss && in_array($__ss, ['loaded','in_transit','delivered']) ? 'done' : ($order['status'] === 'shipping' ? 'current' : '') ?>">👤</span><span class="step-dot <?= $__ss && in_array($__ss, ['in_transit','delivered']) ? 'done' : ($order['status'] === 'shipping' && $__ss === 'loaded' ? '' : ($order['status'] === 'shipping' ? 'current' : '')) ?>">🚚</span><span class="step-dot <?= $order['status'] === 'completed' ? 'done' : '' ?>">🎉</span></div><div class="order-body"><div style="display:flex;gap:.5rem;align-items:center"><?php foreach (array_slice($order['items'], 0, 4) as $item): ?><div class="item-thumb"><?php if ($item['image']): ?><img src="<?= e(product_image($item['image'])) ?>" alt=""><?php else: ?>🐟<?php endif; ?></div><?php endforeach; ?><span style="font-size:.85rem;color:var(--muted);margin-left:.5rem"><?= count($order['items']) ?> item(s)</span></div><div style="font-size:1.25rem;font-weight:900;color:var(--amber-light)">RM <?= e(formatted_money((float) $order['total_amount'])) ?></div></div></div><?php endforeach; ?><?php else: ?><div class="empty-state"><div style="font-size:5rem;margin-bottom:1.5rem">📦</div><h2 style="font-family:var(--font-display);font-size:1.5rem;margin-bottom:.75rem">No Orders Yet</h2><p style="color:var(--muted);margin-bottom:2rem">Go shop for some fresh ingredients!</p><a href="<?= url_for('shop') ?>" class="btn btn-primary btn-lg">🛒 Start Shopping</a></div><?php endif; ?></div>
